/// <summary>
/// Determines if the AX DB is running in SQL Azure or SQL Server.
/// </summary>
/// <returns>
/// True if SQL Azure, false otherwise.
/// </returns>
public static boolean isSqlAzure()
{
    return DBMSQLUtils::getSqlEdition() == 'SQL Azure';
}

/// <summary>
/// Returns the Server property 'Edition' from SQL. (i.e. 'SQL Azure', 'Enterprise Evaluation Edition (64-bit)', etc).
/// </summary>
/// <returns>
/// String representing the Edition of the SQL Server.
/// </returns>
public static str getSqlEdition()
{
    str sqlStatementText;
    Connection connection = new Connection();

    SqlStatementExecutePermission permission;
    Statement statement;
    ResultSet sqlResult;
    str edition;

    sqlStatementText = 'SELECT SERVERPROPERTY(\'Edition\')';
    permission = new SqlStatementExecutePermission(sqlStatementText);

    // Open the code access permission scope.
    permission.assert();

    statement = connection.createStatement();
    sqlResult = statement.executeQueryWithParameters(sqlStatementText, SqlParams::create());

    edition = '';
    if (sqlResult.next())
    {
        edition = sqlResult.getString(1);
    }

    sqlResult.close();
    statement.close();
    CodeAccessPermission::revertAssert();

    return edition;
}

    public static DBMSqlText getSqlTextSample(DBMSQLHandle _sqlHandle, DBMSQLHandle _planHandle, int _startOffset, int _endOffset)
    {
        str sqlStatementText;
        Connection connection = new Connection();
        SqlStatementExecutePermission permission;
        Statement statement;
        ResultSet sqlResult;
        DBMSqlText QuerySqlText;
        str sqlQuery = strFmt(@"
DECLARE @ParmText NVARCHAR(MAX);
DECLARE @PlanXML XML
select @PlanXML = query_plan
from sys.dm_exec_query_plan(%1);

WITH XMLNAMESPACES (DEFAULT 'http://schemas.microsoft.com/sqlserver/2004/07/showplan')
select @ParmText = STRING_AGG('DECLARE ' + parmTable.parmName + ' ' + parmTable.parmDataType + ' = ' + parmTable.parmValue, '; ')
    from (
SELECT
    p.pList.value('@Column', 'NVARCHAR(128)') AS ParmName,
    p.pList.value('@ParameterDataType', 'NVARCHAR(128)') AS ParmDataType,
    COALESCE(
        p.pList.value('@ParameterRuntimeValue', 'NVARCHAR(MAX)'),
        p.pList.value('@ParameterCompiledValue', 'NVARCHAR(MAX)')
    ) AS parmValue
FROM @PlanXML.nodes('//ParameterList/ColumnReference') AS p(pList)) as parmTable;
        DECLARE @Size INT = 512;
        WITH Chunks AS (
    SELECT CAST(SUBSTRING(@Parmtext, 1, @Size) AS NVARCHAR(512)) AS TextFragment,
           @Size + 1 AS NextPos
    UNION ALL
    SELECT CAST(SUBSTRING(@Parmtext, NextPos, @Size) AS NVARCHAR(512)),
           NextPos + @Size
    FROM Chunks
    WHERE NextPos <= LEN(@Parmtext)
            )
            SELECT * FROM Chunks
            OPTION (MAXRECURSION 0)

    ", _planHandle);
        permission = new SqlStatementExecutePermission(sqlQuery);

        // Open the code access permission scope.
        permission.assert();
        statement = connection.createStatement();
        sqlResult = statement.executeQueryWithParameters(sqlQuery, SqlParams::create());
        str parmText;

        while (sqlResult.next())
        {
            parmText += sqlResult.getString(1);
        }
        sqlResult.close();
        statement.close();
        CodeAccessPermission::revertAssert();

        str sqlStatementTextParametrized = strFmt(@'
    DECLARE @QueryText NVARCHAR(MAX);
SELECT TOP 1 @Querytext = CONVERT(NVARCHAR(MAX), SUBSTRING(st.text, (%2/2)+1,
        ((CASE %2
          WHEN -1 THEN DATALENGTH(st.text)
         ELSE %3
         END - %2)/2) + 1))
FROM sys.dm_exec_sql_text(%1) AS st;
        DECLARE @Size INT = 512;
        WITH Chunks AS (
    SELECT CAST(SUBSTRING(@Querytext, 1, @Size) AS NVARCHAR(512)) AS TextFragment,
           @Size + 1 AS NextPos
    UNION ALL
    SELECT CAST(SUBSTRING(@Querytext, NextPos, @Size) AS NVARCHAR(512)),
           NextPos + @Size
    FROM Chunks
    WHERE NextPos <= LEN(@Querytext)
            )
            SELECT * FROM Chunks
            OPTION (MAXRECURSION 0)'
,_sqlHandle,_startOffset,_endOffset);
        str sqlStatementTextSimple = strFmt(@'
    DECLARE @QueryText NVARCHAR(MAX);
SELECT TOP 1 @Querytext = CONVERT(NVARCHAR(MAX), st.text)
FROM sys.dm_exec_sql_text(%1) AS st;
        DECLARE @Size INT = 512;
        WITH Chunks AS (
    SELECT CAST(SUBSTRING(@Querytext, 1, @Size) AS NVARCHAR(512)) AS TextFragment,
           @Size + 1 AS NextPos
    UNION ALL
    SELECT CAST(SUBSTRING(@Querytext, NextPos, @Size) AS NVARCHAR(512)),
           NextPos + @Size
    FROM Chunks
    WHERE NextPos <= LEN(@Querytext)
            )
            SELECT * FROM Chunks
            OPTION (MAXRECURSION 0)'
,_sqlHandle,_startOffset,_endOffset);
        if (parmText)
        {
            sqlStatementText = sqlStatementTextParametrized;
        }
        else
        {
            sqlStatementText = sqlStatementTextSimple;
        }
        permission = new SqlStatementExecutePermission(sqlStatementText);
        // Open the code access permission scope.
        permission.assert();
        Map parms  = SqlParams::create();
        statement = connection.createStatement();
        sqlResult = statement.executeQueryWithParameters(sqlStatementText, SqlParams::create());

        while(sqlResult.next())
        {
            querySqlText += sqlResult.getString(1);
        }

        sqlResult.close();
        statement.close();
        CodeAccessPermission::revertAssert();

        if (parmText)
        {
            querySqlText = parmText +'\n' + querySQLText;
        }


        return querySqlText;
    }

public static void dropPlanFromCache(DBMSQLHandle _planHandle = '')
{
    str sqlStatementText;
    Connection connection = new Connection();
    SqlStatementExecutePermission permission;
    Statement statement;
    ResultSet sqlResult;
    sqlStatementText = strFmt(@'ALTER DATABASE SCOPED CONFIGURATION CLEAR PROCEDURE_CACHE %1',_planHandle);
    permission = new SqlStatementExecutePermission(sqlStatementText);
    // Open the code access permission scope.
    permission.assert();
    Map parms  = SqlParams::create();
    statement = connection.createStatement();
    statement.executeUpdateWithParameters(sqlStatementText, SqlParams::create());

    statement.close();
    CodeAccessPermission::revertAssert();

}

    public static XML getQueryPlan(DBMSQLHandle _planHandle)
    {
        str sqlStatementText;
        Connection connection = new Connection();
        SqlStatementExecutePermission permission;
        Statement statement;
        ResultSet sqlResult;
        XML QueryPlan;
        sqlStatementText = strFmt(@'
    DECLARE @SQLPlan NVARCHAR(MAX);
SELECT TOP 1 @SQLPlan = CONVERT(NVARCHAR(MAX), query_plan)
FROM sys.dm_exec_query_plan(%1)
        DECLARE @Size INT = 512;
        WITH Chunks AS (
    SELECT CAST(SUBSTRING(@SQLPlan, 1, @Size) AS NVARCHAR(512)) AS PlanFragment,
           @Size + 1 AS NextPos
    UNION ALL
    SELECT CAST(SUBSTRING(@SQLPlan, NextPos, @Size) AS NVARCHAR(512)),
           NextPos + @Size
    FROM Chunks
    WHERE NextPos <= LEN(@SQLPlan)
            )
            SELECT * FROM Chunks
            OPTION (MAXRECURSION 0)',_planHandle);
        permission = new SqlStatementExecutePermission(sqlStatementText);
        // Open the code access permission scope.
        permission.assert();
        Map parms  = SqlParams::create();
        statement = connection.createStatement();
        sqlResult = statement.executeQueryWithParameters(sqlStatementText, SqlParams::create());
        System.Text.StringBuilder sb = new System.Text.StringBuilder();

        while (sqlResult.next())
        {
            sb.append(sqlResult.getString(1));
        }
        QueryPlan = sb.toString();
        sqlResult.close();
        statement.close();
        CodeAccessPermission::revertAssert();
        return QueryPlan;
    }

