public static void setPlanAutoCorrectionQueryStore(DBMSQLQueryStoreQueryId _queryId, boolean _enable)
{
    str sqlStatementText;
    str optionMode;
    if (!_enable)
    {
        DBMIsQueryEnabledForAPRC isQueryEnabledForAPRC;
        select firstonly isQueryEnabledForAPRC
        where isQueryEnabledForAPRC.queryId == _queryId;
        if (!isQueryEnabledForAPRC.queryId)
        {
            return;
        }
        optionMode = isQueryEnabledForAPRC.Option;

    }
    else
    {
        optionMode = 'FORCE_LAST_GOOD_PLAN_EXTENDED_CHECK';
    }
    Connection connection = new Connection();
    SqlStatementExecutePermission permission;
    Statement statement;
    ResultSet sqlResult;
    str sqlQuery = "EXECUTE sys.sp_configure_automatic_tuning @OptionMode, 'QUERY', @QueryId, @Option;";
    permission = new SqlStatementExecutePermission(sqlQuery);
    // Open the code access permission scope.
    permission.assert();
    statement = connection.createStatement();
    Map params = SqlParams::create();
    params.add('QueryId', _queryId);
    params.add('OptionMode', optionMode);
    if (_enable)
    {
        params.add('Option', 'ON');
    }
    else
    {
        params.add('Option', 'OFF');
    }
    statement.executeUpdateWithParameters(sqlQuery, params);
    statement.close();
    CodeAccessPermission::revertAssert();
}

/// <summary>
/// Creates a cast expression.
/// </summary>
/// <param name="_returnFieldCastable">
/// A String value that contains the return field expression to cast.
/// </param>
/// <param name="_targetDataType">
/// The type of data to cast to the field value.
/// </param>
/// <returns>
/// A String that contains an expression formatted as a cast expression.
/// </returns>
public static str try_cast(str _returnFieldCastable, str _targetDataType)
{
    return 'TRY_CAST(' + _returnFieldCastable + ' AS '+ _targetDataType +')';
}

